// Column Profiling Engine - Comprehensive Data Analysis
// Profiles each column with statistical analysis, pattern detection, and metadata

const crypto = require('crypto');

// Helper function to generate UUID
function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Helper function to calculate entropy
function calculateEntropy(values) {
  const freq = {};
  values.forEach(v => {
    freq[v] = (freq[v] || 0) + 1;
  });

  let entropy = 0;
  const total = values.length;
  Object.values(freq).forEach(count => {
    const p = count / total;
    entropy -= p * Math.log2(p);
  });

  return entropy;
}

// Helper function to detect data type
function detectDataType(value) {
  if (value === null || value === undefined || value === '') return 'null';
  if (typeof value === 'number') return 'number';
  if (typeof value === 'boolean') return 'boolean';

  const str = String(value);

  // Check for date patterns
  if (!isNaN(Date.parse(str)) && /\d{4}-\d{2}-\d{2}|\d{1,2}\/\d{1,2}\/\d{2,4}/.test(str)) {
    return 'date';
  }

  // Check for number
  if (!isNaN(str) && str.trim() !== '') return 'number';

  // Check for email
  if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(str)) return 'email';

  // Check for URL
  if (/^https?:\/\/.+/.test(str)) return 'url';

  return 'string';
}

// Helper function to extract regex patterns
function extractPatterns(values) {
  const patterns = {};

  values.forEach(v => {
    if (v === null || v === undefined || v === '') return;

    const str = String(v);
    let pattern = str.replace(/\d/g, '9').replace(/[a-z]/gi, 'A');
    patterns[pattern] = (patterns[pattern] || 0) + 1;
  });

  // Return top 5 patterns
  return Object.entries(patterns)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([pattern, count]) => ({ pattern, count }));
}

// Helper function to detect candidate IDs
function isCandidateID(columnName, values, uniquePercent) {
  const name = columnName.toLowerCase();

  // Check if name suggests ID
  if (name.includes('id') || name.includes('key') || name === 'pk') {
    return true;
  }

  // Check if values are unique and sequential or UUID-like
  if (uniquePercent > 95) {
    const sample = values.filter(v => v !== null && v !== undefined).slice(0, 100);
    const hasUUID = sample.some(v => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(v)));
    const hasSequential = sample.every((v, i) => i === 0 || Number(v) === Number(sample[i-1]) + 1);

    return hasUUID || hasSequential;
  }

  return false;
}

// Helper function to detect reference columns
function isReferenceColumn(columnName, values) {
  const name = columnName.toLowerCase();

  // Check for foreign key naming patterns
  if (name.endsWith('_id') || name.endsWith('id') && name !== 'id') {
    return true;
  }

  // Check for reference patterns
  if (name.includes('ref') || name.includes('fk')) {
    return true;
  }

  return false;
}

// Helper function to detect composite key candidates
function detectCompositeKeys(columns) {
  const candidates = [];

  // Look for combinations of 2-3 columns that might form composite keys
  for (let i = 0; i < columns.length; i++) {
    for (let j = i + 1; j < columns.length; j++) {
      const col1 = columns[i];
      const col2 = columns[j];

      if (col1.uniquePercent < 100 && col2.uniquePercent < 100) {
        candidates.push([col1.name, col2.name]);
      }
    }
  }

  return candidates.slice(0, 5); // Return top 5 candidates
}

// Main profiling logic
const results = [];

for (const item of $input.all()) {
  const data = item.json;

  // Extract metadata from input
  const sourceFile = data.fileName || data.source_file || 'unknown';
  const sheetName = data.sheetName || data.sheet_name || null;

  // Get the actual data rows
  let rows = data.data || data.rows || [];

  // If data is in a different structure, try to extract it
  if (rows.length === 0 && typeof data === 'object') {
    // Check if data itself is an array
    if (Array.isArray(data)) {
      rows = data;
    } else {
      // Try to find array property
      const arrayProp = Object.keys(data).find(key => Array.isArray(data[key]));
      if (arrayProp) {
        rows = data[arrayProp];
      }
    }
  }

  if (rows.length === 0) {
    continue;
  }

  const rowCount = rows.length;
  const datasetId = generateUUID();

  // Calculate file hash
  const fileHash = crypto.createHash('md5').update(JSON.stringify(rows)).digest('hex');

  // Get column names
  const columnNames = Object.keys(rows[0] || {});

  // Profile each column
  const columnProfiles = [];

  for (const colName of columnNames) {
    const values = rows.map(row => row[colName]);

    // Calculate null percentage
    const nullCount = values.filter(v => v === null || v === undefined || v === '').length;
    const nullPercent = (nullCount / rowCount) * 100;

    // Calculate unique percentage
    const uniqueValues = new Set(values.filter(v => v !== null && v !== undefined && v !== ''));
    const uniquePercent = (uniqueValues.size / (rowCount - nullCount)) * 100 || 0;

    // Get non-null values for analysis
    const nonNullValues = values.filter(v => v !== null && v !== undefined && v !== '');

    // Detect data types
    const typeDistribution = {};
    nonNullValues.forEach(v => {
      const type = detectDataType(v);
      typeDistribution[type] = (typeDistribution[type] || 0) + 1;
    });

    // Calculate min/max for numeric and string values
    let minValue = null;
    let maxValue = null;

    if (nonNullValues.length > 0) {
      const numericValues = nonNullValues.filter(v => !isNaN(v)).map(Number);
      if (numericValues.length > 0) {
        minValue = Math.min(...numericValues);
        maxValue = Math.max(...numericValues);
      } else {
        // For strings, use length
        const lengths = nonNullValues.map(v => String(v).length);
        minValue = Math.min(...lengths);
        maxValue = Math.max(...lengths);
      }
    }

    // Calculate entropy
    const entropy = nonNullValues.length > 0 ? calculateEntropy(nonNullValues) : 0;

    // Extract regex patterns
    const patterns = extractPatterns(nonNullValues);

    // Create frequency histogram (top 10 values)
    const frequencyMap = {};
    nonNullValues.forEach(v => {
      frequencyMap[v] = (frequencyMap[v] || 0) + 1;
    });

    const frequencyHistogram = Object.entries(frequencyMap)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 10)
      .map(([value, count]) => ({ value, count, percentage: (count / nonNullValues.length) * 100 }));

    // Detect special column types
    const isCandidateId = isCandidateID(colName, nonNullValues, uniquePercent);
    const isReference = isReferenceColumn(colName, nonNullValues);

    // Check for repeated entity attributes (low cardinality)
    const isRepeatedEntity = uniquePercent < 10 && uniquePercent > 0;

    columnProfiles.push({
      name: colName,
      nullPercent: Math.round(nullPercent * 100) / 100,
      uniquePercent: Math.round(uniquePercent * 100) / 100,
      minValue,
      maxValue,
      dataTypeDistribution: typeDistribution,
      regexPatterns: patterns,
      entropyScore: Math.round(entropy * 100) / 100,
      frequencyHistogram,
      isCandidateID: isCandidateId,
      isReferenceColumn: isReference,
      isRepeatedEntityAttribute: isRepeatedEntity,
      sampleValues: nonNullValues.slice(0, 5)
    });
  }

  // Detect composite key candidates
  const compositeKeyCandidates = detectCompositeKeys(columnProfiles);

  // Compile final result
  results.push({
    json: {
      dataset_id: datasetId,
      source_file: sourceFile,
      sheet_name: sheetName,
      row_count: rowCount,
      file_hash: fileHash,
      column_count: columnNames.length,
      columns: columnProfiles,
      composite_key_candidates: compositeKeyCandidates,
      profiled_at: new Date().toISOString()
    }
  });
}

return results;

// Rule Validator - Validates schema integrity and normalization rules

const items = $input.all();
const schemaData = items[0].json;
const config = $('Workflow Configuration').item.json;

// Extract schema and configuration
const schema = schemaData.schema || schemaData;
const fkThreshold = config.fkOverlapThreshold || 0.8;

// Initialize validation results
const validationResults = {
  isValid: true,
  errors: [],
  warnings: [],
  checks: {
    primaryKeyUniqueness: { passed: true, details: [] },
    foreignKeyOverlap: { passed: true, details: [] },
    columnTypeCompatibility: { passed: true, details: [] },
    noOrphanTables: { passed: true, details: [] },
    noOverNormalization: { passed: true, details: [] },
    noUnderNormalization: { passed: true, details: [] }
  }
};

// Helper function to add error
function addError(check, message) {
  validationResults.isValid = false;
  validationResults.errors.push(message);
  validationResults.checks[check].passed = false;
  validationResults.checks[check].details.push(message);
}

// Helper function to add warning
function addWarning(check, message) {
  validationResults.warnings.push(message);
  validationResults.checks[check].details.push(message);
}

// 1. Check Primary Key Uniqueness
for (const table of schema.tables || []) {
  const pkColumns = table.columns.filter(col => col.isPrimaryKey);

  if (pkColumns.length === 0) {
    addError('primaryKeyUniqueness', `Table "${table.name}" has no primary key defined`);
  }

  // Check for duplicate PK column names within the same table
  const pkNames = pkColumns.map(col => col.name);
  const duplicatePKs = pkNames.filter((name, index) => pkNames.indexOf(name) !== index);

  if (duplicatePKs.length > 0) {
    addError('primaryKeyUniqueness', `Table "${table.name}" has duplicate primary key columns: ${duplicatePKs.join(', ')}`);
  }
}

// 2. Check Foreign Key Overlap and Validity
for (const relationship of schema.relationships || []) {
  const sourceTable = schema.tables.find(t => t.name === relationship.sourceTable);
  const targetTable = schema.tables.find(t => t.name === relationship.targetTable);

  if (!sourceTable) {
    addError('foreignKeyOverlap', `Source table "${relationship.sourceTable}" not found for relationship`);
    continue;
  }

  if (!targetTable) {
    addError('foreignKeyOverlap', `Target table "${relationship.targetTable}" not found for relationship`);
    continue;
  }

  const fkColumn = sourceTable.columns.find(col => col.name === relationship.sourceColumn);
  const pkColumn = targetTable.columns.find(col => col.name === relationship.targetColumn);

  if (!fkColumn) {
    addError('foreignKeyOverlap', `Foreign key column "${relationship.sourceColumn}" not found in table "${relationship.sourceTable}"`);
  }

  if (!pkColumn) {
    addError('foreignKeyOverlap', `Referenced column "${relationship.targetColumn}" not found in table "${relationship.targetTable}"`);
  }

  // Check if target column is a primary key
  if (pkColumn && !pkColumn.isPrimaryKey) {
    addWarning('foreignKeyOverlap', `Foreign key in "${relationship.sourceTable}" references non-primary key column "${relationship.targetColumn}" in "${relationship.targetTable}"`);
  }
}

// 3. Check Column Type Compatibility for Foreign Keys
for (const relationship of schema.relationships || []) {
  const sourceTable = schema.tables.find(t => t.name === relationship.sourceTable);
  const targetTable = schema.tables.find(t => t.name === relationship.targetTable);

  if (sourceTable && targetTable) {
    const fkColumn = sourceTable.columns.find(col => col.name === relationship.sourceColumn);
    const pkColumn = targetTable.columns.find(col => col.name === relationship.targetColumn);

    if (fkColumn && pkColumn) {
      // Normalize types for comparison
      const fkType = fkColumn.dataType.toLowerCase().replace(/\(.*\)/, '');
      const pkType = pkColumn.dataType.toLowerCase().replace(/\(.*\)/, '');

      if (fkType !== pkType) {
        addError('columnTypeCompatibility', `Type mismatch: FK "${relationship.sourceTable}.${relationship.sourceColumn}" (${fkColumn.dataType}) does not match PK "${relationship.targetTable}.${relationship.targetColumn}" (${pkColumn.dataType})`);
      }
    }
  }
}

// 4. Check for Orphan Tables (tables with no relationships)
const tablesWithRelationships = new Set();
for (const relationship of schema.relationships || []) {
  tablesWithRelationships.add(relationship.sourceTable);
  tablesWithRelationships.add(relationship.targetTable);
}

for (const table of schema.tables || []) {
  if (!tablesWithRelationships.has(table.name) && schema.tables.length > 1) {
    addWarning('noOrphanTables', `Table "${table.name}" has no relationships with other tables (orphan table)`);
  }
}

// 5. Check for Over-Normalization (too many tables with single columns)
const singleColumnTables = schema.tables.filter(table => 
  table.columns.filter(col => !col.isPrimaryKey).length <= 1
);

if (singleColumnTables.length > schema.tables.length * 0.3) {
  addWarning('noOverNormalization', `Possible over-normalization: ${singleColumnTables.length} tables have only 1-2 columns. Consider consolidating: ${singleColumnTables.map(t => t.name).join(', ')}`);
}

// 6. Check for Under-Normalization (tables with too many columns)
const largeColumnTables = schema.tables.filter(table => table.columns.length > 15);

if (largeColumnTables.length > 0) {
  for (const table of largeColumnTables) {
    addWarning('noUnderNormalization', `Table "${table.name}" has ${table.columns.length} columns. Consider normalizing if there are repeating groups or multi-valued dependencies`);
  }
}

// Check for repeating column patterns (sign of under-normalization)
for (const table of schema.tables || []) {
  const columnNames = table.columns.map(col => col.name.toLowerCase());
  const patterns = {};

  for (const name of columnNames) {
    // Check for numbered columns (e.g., phone1, phone2, phone3)
    const match = name.match(/^(.+?)(\d+)$/);
    if (match) {
      const base = match[1];
      patterns[base] = (patterns[base] || 0) + 1;
    }
  }

  for (const [pattern, count] of Object.entries(patterns)) {
    if (count >= 3) {
      addWarning('noUnderNormalization', `Table "${table.name}" has repeating column pattern "${pattern}*" (${count} occurrences). Consider normalizing into a separate table`);
    }
  }
}

// Prepare output
if (validationResults.isValid) {
  return [
    {
      json: {
        ...schemaData,
        validation: {
          status: 'passed',
          timestamp: new Date().toISOString(),
          checks: validationResults.checks,
          warnings: validationResults.warnings
        }
      }
    }
  ];
} else {
  // Return error with validation details
  return [
    {
      json: {
        error: 'Schema validation failed',
        validationStatus: 'failed',
        errors: validationResults.errors,
        warnings: validationResults.warnings,
        checks: validationResults.checks,
        originalSchema: schemaData
      }
    }
  ];
}

// SQL Schema Generator
// Generates executable SQL CREATE TABLE, ALTER TABLE, and CREATE INDEX statements

const items = $input.all();
const validatedSchema = items[0].json;

// Helper function to map data types to SQL types
function mapToSQLType(dataType, maxLength = null) {
  const typeMap = {
    'string': maxLength && maxLength <= 255 ? `VARCHAR(${maxLength})` : 'TEXT',
    'integer': 'INTEGER',
    'bigint': 'BIGINT',
    'decimal': 'DECIMAL(10,2)',
    'float': 'FLOAT',
    'double': 'DOUBLE',
    'boolean': 'BOOLEAN',
    'date': 'DATE',
    'datetime': 'DATETIME',
    'timestamp': 'TIMESTAMP',
    'text': 'TEXT',
    'json': 'JSON'
  };
  return typeMap[dataType.toLowerCase()] || 'VARCHAR(255)';
}

// Generate CREATE TABLE statements
let sqlScript = "-- ============================================\n";
sqlScript += "-- SQL Schema Generated by AI Schema Builder\n";
sqlScript += `-- Generated: ${new Date().toISOString()}\n`;
sqlScript += "-- ============================================\n\n";

// First pass: Create all tables
for (const table of validatedSchema.tables) {
  sqlScript += `-- Table: ${table.name}\n`;
  if (table.description) {
    sqlScript += `-- Description: ${table.description}\n`;
  }
  sqlScript += `CREATE TABLE ${table.name} (\n`;

  const columnDefs = [];

  for (const column of table.columns) {
    let colDef = `  ${column.name} ${mapToSQLType(column.dataType, column.maxLength)}`;

    // Add constraints
    if (column.isPrimaryKey) {
      colDef += ' PRIMARY KEY';
    }
    if (column.isUnique && !column.isPrimaryKey) {
      colDef += ' UNIQUE';
    }
    if (!column.nullable) {
      colDef += ' NOT NULL';
    }
    if (column.defaultValue !== undefined && column.defaultValue !== null) {
      colDef += ` DEFAULT ${typeof column.defaultValue === 'string' ? `'${column.defaultValue}'` : column.defaultValue}`;
    }
    if (column.autoIncrement) {
      colDef += ' AUTO_INCREMENT';
    }

    columnDefs.push(colDef);
  }

  sqlScript += columnDefs.join(',\n');
  sqlScript += "\n);\n\n";
}

// Second pass: Add foreign key constraints
if (validatedSchema.relationships && validatedSchema.relationships.length > 0) {
  sqlScript += "-- ============================================\n";
  sqlScript += "-- Foreign Key Relationships\n";
  sqlScript += "-- ============================================\n\n";

  for (const rel of validatedSchema.relationships) {
    sqlScript += `-- Relationship: ${rel.name || `${rel.fromTable}_${rel.toTable}`}\n`;
    if (rel.description) {
      sqlScript += `-- Description: ${rel.description}\n`;
    }

    const constraintName = `fk_${rel.fromTable}_${rel.fromColumn}_${rel.toTable}_${rel.toColumn}`;
    sqlScript += `ALTER TABLE ${rel.fromTable}\n`;
    sqlScript += `  ADD CONSTRAINT ${constraintName}\n`;
    sqlScript += `  FOREIGN KEY (${rel.fromColumn})\n`;
    sqlScript += `  REFERENCES ${rel.toTable}(${rel.toColumn})`;

    if (rel.onDelete) {
      sqlScript += `\n  ON DELETE ${rel.onDelete.toUpperCase()}`;
    }
    if (rel.onUpdate) {
      sqlScript += `\n  ON UPDATE ${rel.onUpdate.toUpperCase()}`;
    }

    sqlScript += ";\n\n";
  }
}

// Third pass: Create indexes
if (validatedSchema.indexes && validatedSchema.indexes.length > 0) {
  sqlScript += "-- ============================================\n";
  sqlScript += "-- Indexes\n";
  sqlScript += "-- ============================================\n\n";

  for (const index of validatedSchema.indexes) {
    sqlScript += `-- Index: ${index.name}\n`;
    if (index.description) {
      sqlScript += `-- Description: ${index.description}\n`;
    }

    const indexType = index.isUnique ? 'UNIQUE INDEX' : 'INDEX';
    const columns = Array.isArray(index.columns) ? index.columns.join(', ') : index.columns;

    sqlScript += `CREATE ${indexType} ${index.name}\n`;
    sqlScript += `  ON ${index.tableName}(${columns});\n\n`;
  }
}

sqlScript += "-- ============================================\n";
sqlScript += "-- End of Schema\n";
sqlScript += "-- ============================================\n";

return [{
  json: {
    sqlSchema: sqlScript,
    tableCount: validatedSchema.tables.length,
    relationshipCount: validatedSchema.relationships?.length || 0,
    indexCount: validatedSchema.indexes?.length || 0
  }
}];

// Get the SQL schema and validation results from previous nodes
const sqlSchema = $input.first().json.sqlSchema || [];
const validationResults = $input.first().json.validationResults || {};
const schemaAnalysis = $input.first().json.schemaAnalysis || {};

// Generate Data Dictionary
const dataDictionary = [];

for (const table of sqlSchema) {
  const tableName = table.tableName;
  const columns = table.columns || [];

  for (const column of columns) {
    const dictEntry = {
      tableName: tableName,
      columnName: column.name,
      dataType: column.type,
      constraints: [],
      sourceColumns: column.sourceColumns || [],
      description: column.description || ''
    };

    // Add constraints
    if (column.primaryKey) {
      dictEntry.constraints.push('PRIMARY KEY');
    }
    if (column.notNull) {
      dictEntry.constraints.push('NOT NULL');
    }
    if (column.unique) {
      dictEntry.constraints.push('UNIQUE');
    }
    if (column.foreignKey) {
      dictEntry.constraints.push(`FOREIGN KEY -> ${column.foreignKey.table}.${column.foreignKey.column}`);
    }

    dataDictionary.push(dictEntry);
  }
}

// Generate ERD in Mermaid format
let erdDiagram = 'erDiagram\n';

// Add tables and their columns
for (const table of sqlSchema) {
  const tableName = table.tableName;
  erdDiagram += `  ${tableName} {\n`;

  for (const column of table.columns || []) {
    let columnDef = `    ${column.type} ${column.name}`;

    // Add key indicators
    if (column.primaryKey) {
      columnDef += ' PK';
    }
    if (column.foreignKey) {
      columnDef += ' FK';
    }
    if (column.unique) {
      columnDef += ' "UNIQUE"';
    }
    if (column.notNull) {
      columnDef += ' "NOT NULL"';
    }

    erdDiagram += columnDef + '\n';
  }

  erdDiagram += '  }\n';
}

// Add relationships
const relationships = [];
for (const table of sqlSchema) {
  for (const column of table.columns || []) {
    if (column.foreignKey) {
      const relationship = {
        from: table.tableName,
        to: column.foreignKey.table,
        cardinality: column.foreignKey.cardinality || 'many-to-one'
      };
      relationships.push(relationship);
    }
  }
}

// Add relationship lines to ERD
for (const rel of relationships) {
  let cardinalitySymbol = '';

  switch (rel.cardinality) {
    case 'one-to-one':
      cardinalitySymbol = '||--||';
      break;
    case 'one-to-many':
      cardinalitySymbol = '||--o{';
      break;
    case 'many-to-one':
      cardinalitySymbol = '}o--||';
      break;
    case 'many-to-many':
      cardinalitySymbol = '}o--o{';
      break;
    default:
      cardinalitySymbol = '}o--||';
  }

  erdDiagram += `  ${rel.from} ${cardinalitySymbol} ${rel.to} : "references"\n`;
}

// Return the results
return [
  {
    json: {
      dataDictionary: dataDictionary,
      erdDiagram: erdDiagram,
      sqlSchema: sqlSchema,
      validationResults: validationResults,
      schemaAnalysis: schemaAnalysis
    }
  }
];
